-- Deletar os carimbos do histórico
DELETE FROM loyaltyStamps WHERE loyaltyCardId IN (
  SELECT id FROM loyaltyCards WHERE customerPhone LIKE '%999290000%'
);

-- Zerar os contadores do cartão e remover cupom ativo
UPDATE loyaltyCards 
SET stamps = 0, totalStampsEarned = 0, couponsEarned = 0, activeCouponId = NULL
WHERE customerPhone LIKE '%999290000%';

-- Verificar o estado
SELECT id, customerPhone, stamps, totalStampsEarned, couponsEarned, activeCouponId 
FROM loyaltyCards 
WHERE customerPhone LIKE '%999290000%';

